import{_ as o,o as r,c as t,a3 as a}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Notely Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md","lastUpdated":1784604242000}'),i={name:"troubleshooting.md"};function s(l,e,n,d,p,c){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="notely-troubleshooting" tabindex="-1">Notely Troubleshooting <a class="header-anchor" href="#notely-troubleshooting" aria-label="Permalink to &quot;Notely Troubleshooting&quot;">​</a></h1><p>Use this page to quickly fix common issues.</p><h2 id="_1-notes-are-not-showing" tabindex="-1">1. Notes Are Not Showing <a class="header-anchor" href="#_1-notes-are-not-showing" aria-label="Permalink to &quot;1. Notes Are Not Showing&quot;">​</a></h2><ol><li>Open <strong>File -&gt; Open Workspace</strong>.</li><li>Confirm the selected folder is correct.</li><li>Check that the folder contains <code>.md</code> files.</li></ol><p>If still empty, restart the app and re-open the same folder.</p><h2 id="_2-preview-looks-wrong" tabindex="-1">2. Preview Looks Wrong <a class="header-anchor" href="#_2-preview-looks-wrong" aria-label="Permalink to &quot;2. Preview Looks Wrong&quot;">​</a></h2><ol><li>Switch to <strong>Split</strong> view.</li><li>Check for markdown validation warnings.</li><li>Fix heading/list/table syntax first.</li></ol><p>For Mermaid diagrams, validate the Mermaid block syntax before retrying preview.</p><h2 id="_3-a-linked-file-or-image-does-not-open" tabindex="-1">3. A Linked File or Image Does Not Open <a class="header-anchor" href="#_3-a-linked-file-or-image-does-not-open" aria-label="Permalink to &quot;3. A Linked File or Image Does Not Open&quot;">​</a></h2><ol><li>Check that the file still exists in your workspace.</li><li>Verify the path in markdown is correct.</li><li>Reinsert the link from toolbar/file picker if needed.</li></ol><h2 id="_4-sync-conflicts-keep-appearing" tabindex="-1">4. Sync Conflicts Keep Appearing <a class="header-anchor" href="#_4-sync-conflicts-keep-appearing" aria-label="Permalink to &quot;4. Sync Conflicts Keep Appearing&quot;">​</a></h2><ol><li>Open <strong>P2P -&gt; P2P Status</strong>.</li><li>Confirm peers are connected and trusted.</li><li>Open conflict tools and resolve each conflict.</li></ol><p>After resolving, refresh the note list and verify final content.</p><h2 id="_5-ai-features-are-disabled" tabindex="-1">5. AI Features Are Disabled <a class="header-anchor" href="#_5-ai-features-are-disabled" aria-label="Permalink to &quot;5. AI Features Are Disabled&quot;">​</a></h2><ol><li>Open <strong>AI -&gt; AI Settings</strong>.</li><li>Confirm your AI sign-in details are saved.</li><li>Run connection test.</li></ol><p>If a feature still does not appear, the AI service you chose may not support it.</p><h2 id="_6-app-feels-slow-in-large-workspaces" tabindex="-1">6. App Feels Slow in Large Workspaces <a class="header-anchor" href="#_6-app-feels-slow-in-large-workspaces" aria-label="Permalink to &quot;6. App Feels Slow in Large Workspaces&quot;">​</a></h2><ul><li>Use folder structure to reduce very large flat note lists.</li><li>Close unused views (for example, graph or media-heavy previews).</li><li>Refresh AI search data only when you actually need it.</li></ul><h2 id="_7-quick-support-details-to-share" tabindex="-1">7. Quick Support Details to Share <a class="header-anchor" href="#_7-quick-support-details-to-share" aria-label="Permalink to &quot;7. Quick Support Details to Share&quot;">​</a></h2><p>If you need help from your team, share:</p><ul><li>App version from <strong>Help -&gt; About Notely</strong></li><li>What you were doing when issue started</li><li>Exact error message text (if shown)</li></ul><h2 id="_8-screen-capture-mode-looks-incorrect-a-r" tabindex="-1">8. Screen Capture Mode Looks Incorrect (A/R) <a class="header-anchor" href="#_8-screen-capture-mode-looks-incorrect-a-r" aria-label="Permalink to &quot;8. Screen Capture Mode Looks Incorrect (A/R)&quot;">​</a></h2><ol><li>Open <strong>Settings -&gt; Screen Capture</strong> and choose mode again.</li><li>Check toolbar capture icon marker. <code>A</code> means Auto Insert and <code>R</code> means Review Before Insert.</li><li>Trigger a fresh capture (<code>Ctrl/Cmd + Shift + S</code>) to confirm behavior.</li></ol><p>If marker and menu differ, restart app once and re-check.</p><h2 id="_9-review-mode-save-appears-unresponsive" tabindex="-1">9. Review Mode Save Appears Unresponsive <a class="header-anchor" href="#_9-review-mode-save-appears-unresponsive" aria-label="Permalink to &quot;9. Review Mode Save Appears Unresponsive&quot;">​</a></h2><p>In current flow, review mode Save should work even without making edits.</p><p>If Save still appears blocked:</p><ol><li>Ensure review dialog is focused.</li><li>Confirm image preview has loaded.</li><li>Try keyboard Enter once.</li><li>Retry capture from toolbar.</li></ol><h2 id="_10-embedded-terminal-does-not-start" tabindex="-1">10. Embedded Terminal Does Not Start <a class="header-anchor" href="#_10-embedded-terminal-does-not-start" aria-label="Permalink to &quot;10. Embedded Terminal Does Not Start&quot;">​</a></h2><ol><li>Open <strong>View -&gt; Show Terminal</strong> again.</li><li>Switch shell from <strong>View -&gt; Terminal Shell</strong> and retry.</li><li>If strict terminal policy is configured, confirm your command is allowed.</li></ol><p>If the terminal still fails, capture the exact error text shown in the terminal panel.</p><h2 id="_11-workspace-export-does-not-finish" tabindex="-1">11. Workspace Export Does Not Finish <a class="header-anchor" href="#_11-workspace-export-does-not-finish" aria-label="Permalink to &quot;11. Workspace Export Does Not Finish&quot;">​</a></h2><ol><li>Retry export from the landing screen.</li><li>Confirm the destination folder is writable.</li><li>Try <strong>Notes as-is</strong> first to isolate PDF or web export issues.</li></ol><p>If PDF-only export fails, retry with a smaller workspace to identify a problematic note or asset.</p><h2 id="_12-project-website-shows-notes-from-an-older-workspace" tabindex="-1">12. Project Website Shows Notes from an Older Workspace <a class="header-anchor" href="#_12-project-website-shows-notes-from-an-older-workspace" aria-label="Permalink to &quot;12. Project Website Shows Notes from an Older Workspace&quot;">​</a></h2><ol><li>Confirm workspace was changed from <strong>File -&gt; Open Workspace</strong> and opened successfully.</li><li>Re-open website using <strong>Web -&gt; Open Project Website</strong> from the landing screen.</li><li>If browser tab is pinned, open a new tab/window once.</li></ol><p>If this keeps happening, update to the latest build that includes workspace-switch website scope refresh fixes.</p>',37)])])}const f=o(i,[["render",s]]);export{u as __pageData,f as default};
